   103→{
   104→	struct nfp_ccm_mbox_cmsg_cb *cb = (void *)skb->cb;
   105→
   106→	return cb->posted;
   107→}
   108→
   109→static void nfp_ccm_mbox_mark_posted(struct sk_buff *skb)
   110→{
